    /* ── MCP connection health check ── */
    let _mcpHealthTimer = null;

    function setMcpConnTag(state) {
        // state: 'checking' | 'connected' | 'disconnected'
        const tag = $('mcp-conn-tag');
        const lbl = $('mcp-conn-label');
        if (!tag) return;
        tag.className = `mcp-conn-tag mcp-conn-tag--${state}`;
        if (lbl) lbl.textContent = state === 'connected' ? '已连接' : state === 'disconnected' ? '未连接' : '检测中';
    }

    async function checkMcpHealth() {
        try {
            const res = await fetch('http://127.0.0.1:3142/health', {
                signal: AbortSignal.timeout(2000)
            });
            if (res.ok) {
                const data = await res.json().catch(() => ({}));
                const count = data.sopCount ?? 0;
                const lbl = $('mcp-conn-label');
                if (lbl) lbl.textContent = count > 0 ? `已连接 · ${count} 个SOP` : '已连接';
                const tag = $('mcp-conn-tag');
                if (tag) tag.className = 'mcp-conn-tag mcp-conn-tag--connected';
            } else {
                setMcpConnTag('disconnected');
            }
        } catch {
            setMcpConnTag('disconnected');
        }
    }

    function startMcpHealthPolling() {
        clearInterval(_mcpHealthTimer);
        checkMcpHealth();
        _mcpHealthTimer = setInterval(checkMcpHealth, 10000);
    }

    function stopMcpHealthPolling() {
        clearInterval(_mcpHealthTimer);
        _mcpHealthTimer = null;
    }

    /* ── Push button click ── */
    $('btn-push-mcp')?.addEventListener('click', async () => {
        if (!currentSOP) return;
        const sopJson = buildSopJson(currentSOP);
        setMcpConnTag('checking');
        const result = await pushToMcpServerWithResult(sopJson);
        if (result.success) {
            // Show prompt hint panel with SOP id + title for confirmation
            const panel      = $('push-prompt-panel');
            const hint       = $('push-hint-text');
            const idBadge    = $('push-sop-id');
            const promptText = $('push-prompt-text');
            const titleEl    = $('push-sop-title');
            const sopTitle   = sopJson.title || currentSOP?.startTitle || '未命名 SOP';
            const sopId      = result.id || '';
            if (idBadge  && sopId)    idBadge.textContent  = sopId;
            if (titleEl  && sopTitle) titleEl.textContent  = sopTitle;
            // Build a precise prompt so Claude Code can target this exact SOP
            if (promptText && sopId) {
                promptText.textContent = `调用 sop-skill 工具，获取 SOP（ID: ${sopId}，标题：${sopTitle}），生成 Playwright 测试脚本写入 tests/ 目录，运行测试并修复错误直到通过`;
            }
            // Update verify tip to show expected title echo
            const verifyTip = $('push-verify-tip-text');
            if (verifyTip && sopTitle) {
                verifyTip.textContent = `Claude Code 回复时会提到「${sopTitle}」，那就是收到的确认`;
            }
            if (panel) panel.style.display = 'flex';
            if (hint)  hint.style.display  = 'none';
            // Auto-copy the prompt text so user can paste immediately into Claude Code
            const promptStr = promptText?.textContent?.trim();
            if (promptStr) {
                navigator.clipboard.writeText(promptStr).catch(() => {});
                toast('✓ 已推送，提示词已自动复制');
            }
            // Refresh health badge immediately so sopCount updates
            checkMcpHealth();
        } else if (result.error === 'TIMEOUT') {
            setMcpConnTag('disconnected');
            toast(t('sopPushTimeout'));
        } else {
            setMcpConnTag('disconnected');
            toast(t('sopPushFailed', { msg: '请确认 sop-mcp-server 已运行 (npx sop-mcp-server)' }));
        }
    });

    /* Copy prompt text */
