    function checkComicUnlocked() {
        return new Promise(resolve => {
            try {
                chrome.storage.local.get(HISTORY_KEY, r => {
                    const data = r || {};
                    resolve(Array.isArray(data[HISTORY_KEY]) && data[HISTORY_KEY].length > 0);
                });
            } catch(e) { resolve(false); }
        });
    }

    async function buildComicPage() {
        if (comicBuilt || !comicChaptersEl) return;
        comicBuilt = true;
        const unlocked = await checkComicUnlocked();
        CHAPTERS[2].locked = !unlocked;
        CHAPTERS[3].locked = !unlocked;
        comicChaptersEl.innerHTML = '';
        CHAPTERS.forEach(ch => {
            const card = document.createElement('div');
            card.className = 'comic-card' + (ch.locked ? ' locked' : '') + (ch.coming ? ' coming' : '');
            const coverSrc = 'data:image/jpeg;base64,' + COMIC_DATA[ch.coverKey];
            const lockBadge = ch.coming
                ? '<div class="comic-lock-badge"><span>连载中，敬请期待</span></div>'
                : (ch.locked ? '<div class="comic-lock-badge"><svg width="20" height="20" viewBox="0 0 16 16" fill="none"><path d="M5 7V5a3 3 0 016 0v2" stroke="#fff" stroke-width="1.4" stroke-linecap="round"/><rect x="3.5" y="7" width="9" height="7" rx="1.5" stroke="#fff" stroke-width="1.4"/></svg><span>完成首次录制后解锁</span></div>' : '');
            const tag = ch.chapter ? '<span class="comic-card-tag">' + ch.chapter + '</span>' : '';
            const desc = ch.desc ? '<div class="comic-card-desc">' + ch.desc + '</div>' : '';
            const noInfo = ch.coming && !ch.chapter;
            const infoHtml = noInfo ? '' :
                '<div class="comic-card-info">' +
                '<div class="comic-card-head">' + tag +
                '<span class="comic-card-title">' + ch.title + '</span></div>' +
                desc +
                '</div>';
            card.innerHTML =
                '<img class="comic-card-cover' + (noInfo ? ' full-radius' : '') + '" src="' + coverSrc + '" alt="" draggable="false">' +
                infoHtml +
                lockBadge;
            card.addEventListener('click', () => {
                if (ch.locked) {
                    toast(ch.coming ? '连载中，敬请期待～' : '先去录制你的第一个任务吧！');
                    return;
                }
                openComicChapter(ch);
            });
            comicChaptersEl.appendChild(card);
        });
    }

    function openComicChapter(ch) {
        if (!comicViewerEl || !comicPanelsEl) return;
        comicChapterIdx = CHAPTERS.indexOf(ch);
        if (comicHeaderTitle) comicHeaderTitle.textContent = ch.chapter + '：' + ch.title;
        // Show "next chapter" button if there's a valid next chapter
        const hasNext = comicChapterIdx >= 0 && comicChapterIdx < CHAPTERS.length - 1;
        if (btnComicNext) btnComicNext.classList.toggle('hidden', !hasNext);
        comicPanelsEl.innerHTML = '';
        const panels = COMIC_DATA[ch.panelsKey];
        if (Array.isArray(panels)) {
            panels.forEach(src => {
                const img = document.createElement('img');
                img.className = 'comic-panel';
                img.src = 'data:image/jpeg;base64,' + src;
                img.alt = '';
                img.draggable = false;
                comicPanelsEl.appendChild(img);
            });
        } else {
            const hint = document.createElement('div');
            hint.className = 'comic-coming-hint';
            hint.innerHTML = '<span class="comic-coming-emoji">✏️</span><span>正在创作中，敬请期待…</span>';
            comicPanelsEl.appendChild(hint);
        }
        comicChaptersEl.classList.add('hidden');
        comicViewerEl.classList.remove('hidden');
    }

    function closeComicViewer() {
        if (comicViewerEl) comicViewerEl.classList.add('hidden');
        if (comicChaptersEl) comicChaptersEl.classList.remove('hidden');
        if (comicHeaderTitle) comicHeaderTitle.textContent = I18N[uiLocale]?.comicTitle || 'PP连载漫画';
        if (btnComicNext) btnComicNext.classList.add('hidden');
        comicChapterIdx = -1;
    }

    async function openComicPage() {
        comicBuilt = false; // Rebuild each time to re-check unlock
        await buildComicPage();
        closeComicViewer();
        switchView('comic');
    }

    btnComic?.addEventListener('click', openComicPage);
    $('btn-comic-back')?.addEventListener('click', () => {
        if (comicViewerEl && !comicViewerEl.classList.contains('hidden')) {
            closeComicViewer();
        } else {
            switchView('idle');
        }
    });
    btnComicNext?.addEventListener('click', () => {
        const nextIdx = comicChapterIdx + 1;
        if (nextIdx >= 0 && nextIdx < CHAPTERS.length) {
            const nextCh = CHAPTERS[nextIdx];
            if (nextCh.locked) {
                toast(nextCh.coming ? '连载中，敬请期待～' : '先去录制你的第一个任务吧！');
                return;
            }
            openComicChapter(nextCh);
        }
    });

